const body = $input.first().json.body;
const messages = body.messages || [];
const systemPrompt = body.systemPrompt || '';
const language = body.language || 'en';
const role = body.role || 'teacher';

const formattedMessages = [
  { role: 'system', content: systemPrompt },
  ...messages.slice(-10).map(m => ({ role: m.role, content: m.content }))
];

return [{ json: { formattedMessages, language, role } }];

const content = $input.first().json.message?.content || $input.first().json.text || '';

let corrections = [];
let vocabulary = [];
let grammarNote = '';

const tipMatches = content.match(/📝[^\n]+/g);
if (tipMatches) corrections = tipMatches.map(t => t.replace(/📝\s*/, ''));

const vocabMatches = content.match(/\*\*([^*]+)\*\*\s*[=:–-]\s*([^\n]+)/g);
if (vocabMatches) vocabulary = vocabMatches.slice(0, 3).map(v => v.replace(/\*\*/g, ''));

const grammarMatch = content.match(/(?:Grammar|Ngữ pháp|文法|语法|문법)[:\s]*([^\n]+)/i);
if (grammarMatch) grammarNote = grammarMatch[1];

return [{ json: { output: content, corrections, vocabulary, grammarNote } }];
